firmware_template.source:
#include "queue_ipc.h"
static QueueHandle_t _q=NULL;
void queue_setup(uint8_t len,uint8_t sz){_q=xQueueCreate(len,sz);Serial.printf("[queue] OK len=%d sz=%d\n",len,sz);}
bool queue_send(const void*i,uint32_t ms){return xQueueSend(_q,i,ms/portTICK_PERIOD_MS)==pdTRUE;}
bool queue_receive(void*i,uint32_t ms){return xQueueReceive(_q,i,ms/portTICK_PERIOD_MS)==pdTRUE;}
uint8_t queue_count(){return uxQueueMessagesWaiting(_q);}
